module RefModule(clk,reset,R,S,Out);input reset, clk, R, S;
	 output Out;
	 reg   dataVal;

	   wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, negedge reset or posedge dbg_halt)
		if(!reset)
			dataVal<=0;
		else if(R)
			dataVal<=0;
		else if(S)
			dataVal<=1;
		else 
			dataVal<=dataVal;

		assign Out=dataVal;

	 endmodule
